    #include <filesystem>
namespace fs = std::filesystem;
std::vector<GeneticAlgorithm::Task> get_data() {
  std::vector<GeneticAlgorithm::Task> task = std::move(part1);

  // Укажите путь к вашей папке
    std::string path = "."; // Текущая папка

    try {
        if (fs::exists(path) && fs::is_directory(path)) {
            for (const auto& entry : fs::directory_iterator(path)) {
                if (fs::is_regular_file(entry)) {
                    std::cout << entry.path().filename() << '\n';
                }
            }
        } else {
            std::cout << "Папка не найдена или это не каталог.\n";
        }
    } catch (const fs::filesystem_error& e) {
        std::cerr << "Ошибка доступа: " << e.what() << '\n';
    }

  std::ifstream file("file.txt");
  int digit = 0;
  int count = task.size();
  while (file >> digit) {
    count++;
    GeneticAlgorithm::Task t;
    t.input.resize(1024);
    t.answer.resize(10);
    t.answer[digit] = 1.0;
    for (size_t i = 0; i < 1024; i++) {
      file >> t.input[i];
    }
    task.push_back(std::move(t));
  }
  std::cout << "Считано: " << task.size() << "\n";
  return task;
}